mapper.select:
SELECT id, promotion_no, promotion_name, promotion_desc, promotion_type, target_type, target_value, fee_type, discount_fee_rate, fixed_fee_amount, max_discount_amount, start_time, end_time, duration_days, total_quota, used_quota, per_merchant_quota, status, operator_id, operator_name, remark, created_at, updated_at, deleted FROM fee_promotion
deleted = 0
AND promotion_name LIKE CONCAT('%', #{params.promotionName}, '%')
AND promotion_type = #{params.promotionType}
AND status = #{params.status}
AND created_at >= #{params.startDate}
AND created_at <= #{params.endDate}
ORDER BY created_at DESC
